class CountIterator:
    def __init__(self, n):
        self.n = n
        self.current = 0

    def __next__(self):
        if self.current < self.n:
            val = self.current
            self.current += 1
            return val
        raise StopIteration

# next(CountIterator(3))  → 0
# for i in CountIterator(3): ...  → TypeError: object is not iterable

class CountUpTo:
    def __init__(self, n):
        self.n = n
        self.current = 0

    def __iter__(self):
        return self   # returns self — single use

    def __next__(self):
        if self.current < self.n:
            val = self.current
            self.current += 1
            return val
        raise StopIteration

# for i in CountUpTo(3): print(i, end=" ")  → 0 1 2
